  777: static void set_device_specific_options(struct btrfs_fs_info *fs_info)
  778: {
  779: 	if (!btrfs_test_opt(fs_info, NOSSD) &&
  780: 	    !fs_info->fs_devices->rotating)
  781: 		btrfs_set_opt(fs_info->mount_opt, SSD);
  782: 
  783: 	/*
  784: 	 * For devices supporting discard turn on discard=async automatically,
  785: 	 * unless it's already set or disabled. This could be turned off by
  786: 	 * nodiscard for the same mount.
  787: 	 *
  788: 	 * The zoned mode piggy backs on the discard functionality for
  789: 	 * resetting a zone. There is no reason to delay the zone reset as it is
  790: 	 * fast enough. So, do not enable async discard for zoned mode.
  791: 	 */
  792: 	if (!(btrfs_test_opt(fs_info, DISCARD_SYNC) ||
  793: 	      btrfs_test_opt(fs_info, DISCARD_ASYNC) ||
  794: 	      btrfs_test_opt(fs_info, NODISCARD)) &&
  795: 	    fs_info->fs_devices->discardable &&
  796: 	    !btrfs_is_zoned(fs_info))
  797: 		btrfs_set_opt(fs_info->mount_opt, DISCARD_ASYNC);
  798: }
