 5828: /*
 5829:  * Check if we need to log an inode. This is used in contexts where while
 5830:  * logging an inode we need to log another inode (either that it exists or in
 5831:  * full mode). This is used instead of btrfs_inode_in_log() because the later
 5832:  * requires the inode to be in the log and have the log transaction committed,
 5833:  * while here we do not care if the log transaction was already committed - our
 5834:  * caller will commit the log later - and we want to avoid logging an inode
 5835:  * multiple times when multiple tasks have joined the same log transaction.
 5836:  */
 5837: static bool need_log_inode(const struct btrfs_trans_handle *trans,
 5838: 			   struct btrfs_inode *inode)
 5839: {
 5840: 	/*
 5841: 	 * If a directory was not modified, no dentries added or removed, we can
 5842: 	 * and should avoid logging it.
 5843: 	 */
 5844: 	if (S_ISDIR(inode->vfs_inode.i_mode) && inode->last_trans < trans->transid)
 5845: 		return false;
 5846: 
 5847: 	/*
 5848: 	 * If this inode does not have new/updated/deleted xattrs since the last
 5849: 	 * time it was logged and is flagged as logged in the current transaction,
 5850: 	 * we can skip logging it. As for new/deleted names, those are updated in
 5851: 	 * the log by link/unlink/rename operations.
 5852: 	 * In case the inode was logged and then evicted and reloaded, its
 5853: 	 * logged_trans will be 0, in which case we have to fully log it since
 5854: 	 * logged_trans is a transient field, not persisted.
 5855: 	 */
 5856: 	if (inode_logged(trans, inode, NULL) == 1 &&
 5857: 	    !test_bit(BTRFS_INODE_COPY_EVERYTHING, &inode->runtime_flags))
 5858: 		return false;
 5859: 
 5860: 	return true;
 5861: }
